/// <summary>
/// Check observedDimension
/// </summary>
/// <param name = "_itemid">ItemId</param>
/// <param name = "dimval">DimValue</param>
/// <param name = "Dimgrp">DimGroup</param>
/// <returns></returns>
static boolean checkdimactive(itemid  _itemid,str dimval,Name Dimgrp)
{
    ItemId        varItemId = _itemid;
    FieldId       observedDimension;
    NoYes         isActive;
    EcoResProductDimensionGroup  EcoResProductDimensionGroup= EcoResProductDimensionGroup::findByDimensionGroupName(Dimgrp);

    ;

    if(dimval == 'Configid')
    {
        observedDimension = fieldNum(InventDim, Configid);
    }
    else if(dimval == 'InventColorId')
    {
        observedDimension = fieldNum(InventDim, InventColorId);
    }
    else  if(dimval == 'InventStyleId')
    {
        observedDimension = fieldNum(InventDim, InventStyleId);
    }
    else  if(dimval == 'InventSizeId')
    {
        observedDimension = fieldNum(InventDim, InventSizeId);
    }

    isActive = EcoResProductDimensionGroupFldSetup::findByDimensionGroupFieldId(EcoResProductDimensionGroup.RecId, observedDimension).IsActive;

    return isactive;
}

/// <summary>
/// Creates Transfer journal
/// </summary>
/// <param name = "Recid">Rec Id</param>
public static void CreateTransferJournal(RecId  Recid)
{
    InventJournalTable inventJournalTable;
    InventJournalTrans inventJournalTrans;
    //InventJournalName  inventJournalName = InventJournalName::find(InventParameters::find().ETGBinTransferJournalName;
    JournalCheckPost inventJournalCheckPost;
    NumberSeq num;
    boolean _throwserror=true;
    boolean _showinforesult=false;
    InventDim frominventDim,ToinventDim;
    ETGBinJournalLine         ETGBinJournalLine;
    ETGBinJournalBatchDetails  ETGBinJournalBatchDetails;
    InventDim                   inventDim;
    ;

    ttsbegin;

    select ETGBinJournalLine
        where ETGBinJournalLine.RecId == Recid;

    inventJournalTable.clear();

    num = new NumberSeq();

    num = NumberSeq::newGetNum(InventParameters::numRefTransferId());

    inventJournalTable.initFromInventJournalName(InventJournalName::find(InventParameters::find().ETGBinTransferJournalName));

    inventJournalTable.Description = 'Bin Journal  No. for '+ETGBinJournalLine.JournalId;

    inventJournalTable.SystemBlocked = true;

    inventJournalTable.insert();

    int linecount=0;

    while select ETGBinJournalBatchDetails
          where ETGBinJournalBatchDetails.BinJournalLine == ETGBinJournalLine.RecId
    {

        inventJournalTrans.clear();

        inventJournalTrans.initFromInventJournalTable(inventJournalTable);

        inventJournalTrans.ItemId = ETGBinJournalLine.ItemId;

        inventDim = inventDim::find(ETGBinJournalBatchDetails.GRNInvenDim);

        frominventDim.InventLocationId= inventDim.InventLocationId;
        frominventDim.inventSiteId =inventDim.InventSiteId;
        frominventDim.wMSLocationId = inventDim.wMSLocationId;
        frominventDim.configId =  inventDim.configId;
        frominventDim.InventSizeId =inventDim.InventSizeId;
        frominventDim.InventColorId = inventDim.InventColorId;
        frominventDim.InventStyleId = inventDim.InventStyleId;
        frominventDim.inventBatchId = ETGBinJournalBatchDetails.InventBatch;
        frominventDim.inventSerialId = inventDim.inventSerialId;

        ToinventDim.InventLocationId = ETGBinJournalLine.Warehouse;
        ToinventDim.inventSiteId = ETGBinJournalLine.SiteId; 
        ToinventDim.wMSLocationId = ETGBinJournalLine.Location;
        ToinventDim.configId =   ETGBinJournalLine.Configuration;
        ToinventDim.InventSizeId = ETGBinJournalLine.Size;
        ToinventDim.InventColorId = ETGBinJournalLine.Colour;
        ToinventDim.InventStyleId = ETGBinJournalLine.Style;
        ToinventDim.inventBatchId = ETGBinJournalLine.ToBatch;
        ToinventDim.inventSerialId = inventDim.inventSerialId;


        ToinventDim = InventDim::findOrCreate(ToinventDim);

        frominventDim = InventDim::findOrCreate(frominventDim);

        inventJournalTrans.InventDimId = frominventDim.inventDimId;

        inventJournalTrans.initFromInventTable(InventTable::find(ETGBinJournalLine.ItemId));

        inventJournalTrans.Qty = -ETGBinJournalBatchDetails.GRNQuantity;
        inventJournalTrans.modifiedField(fieldNum(inventJournalTrans,Qty));

        inventJournalTrans.ToInventDimId = ToinventDim.inventDimId;

        inventJournalTrans.TransDate = SystemDateget();

        inventJournalTrans.ETGReasonId = InventJournalName::find(inventJournalTable.JournalNameId).ETGReasonCode;

        inventJournalTrans.insert();
        linecount++;
    }

    InventJournalTable  updateInventJournalTable;

    select firstOnly forUpdate updateInventJournalTable
        where updateInventJournalTable.RecId == inventJournalTable.RecId;

    updateInventJournalTable.SystemBlocked = false;
    updateInventJournalTable.NumOfLines = linecount;
    updateInventJournalTable.update();

    ETGBinJournalLine.selectForUpdate(true);
    ETGBinJournalLine.TransferJRNId = inventJournalTable.JournalId;
    ETGBinJournalLine.doUpdate();

    ttscommit;

    if(inventJournalTable.JournalId)
    {
        Info(strFmt('@ETGReport:ETG101',inventJournalTable.JournalId));
    }
}

/// <summary>
/// creates bin transfer journal lines
/// </summary>
/// <param name = "recid">RecId</param>
/// <param name = "BinJournalLine">BinJournalLine</param>
public static void TransferToBin(RecId recid,RecId BinJournalLine)
{
    VendPackingSlipTrans        VendPackingSlipTrans;
    InventDim                   InventDim;
    ETGBinJournalBatchDetails   ETGBinJournalBatchDetails;
    ETGBinJournalLine           ETGBinJournalLine;
    ETGQtyRequired              _ReqQty;
    LineAmount                  BinValue;


    select * from VendPackingSlipTrans
            where VendPackingSlipTrans.RecId == recid;

    select  InventDim
            where InventDim.inventDimId     == VendPackingSlipTrans.InventDimId;

    select  ETGBinJournalLine
        where ETGBinJournalLine.RecId == BinJournalLine;

    ttsbegin;

    select  ETGBinJournalBatchDetails order by LineNum desc
        where ETGBinJournalBatchDetails.JournalId == ETGBinJournalLine.JournalId
                && ETGBinJournalBatchDetails.BinJournalLine ==  BinJournalLine;

    ETGBinJournalBatchDetails.initValue();

    if(ETGBinJournalBatchDetails.RecId) 
    {
        ETGBinJournalBatchDetails.LineNum = ETGBinJournalBatchDetails.LineNum+1;
    }
    ETGBinJournalBatchDetails.JournalId         = ETGBinJournalLine.JournalId;
    ETGBinJournalBatchDetails.BinJournalLine    = BinJournalLine;
    ETGBinJournalBatchDetails.GRNDate           = VendPackingSlipTrans.DeliveryDate;
    ETGBinJournalBatchDetails.GRNNo             = VendPackingSlipTrans.PackingSlipId;
    ETGBinJournalBatchDetails.GRNInvenDim       = VendPackingSlipTrans.InventDimId;
    ETGBinJournalBatchDetails.ItemId            = VendPackingSlipTrans.ItemId;
    ETGBinJournalBatchDetails.GRNQuantity       = VendPackingSlipTrans.ETGQtyRequired;
    ETGBinJournalBatchDetails.InventBatch       = InventDim.inventBatchId;
    ETGBinJournalBatchDetails.GRNRate           = VendPackingSlipTrans.ETGGRNRate();
    ETGBinJournalBatchDetails.GRNAmount         = ETGBinJournalBatchDetails.GRNQuantity * ETGBinJournalBatchDetails.GRNRate;
    ETGBinJournalBatchDetails.insert();

    _ReqQty = _ReqQty+VendPackingSlipTrans.ETGQtyRequired;
    BinValue = BinValue + ETGBinJournalBatchDetails.GRNAmount;

    VendPackingSlipTrans.selectForUpdate(true);
    VendPackingSlipTrans.ETGQtyBalance = VendPackingSlipTrans.ETGQtyBalance - VendPackingSlipTrans.ETGQtyRequired;
    VendPackingSlipTrans.ETGQtyRequired= VendPackingSlipTrans.ETGQtyBalance;
    VendPackingSlipTrans.doUpdate();

    ETGBinJournalLine.selectForUpdate(true);
    ETGBinJournalLine.BinQty    = ETGBinJournalLine.BinQty+_ReqQty;       
    ETGBinJournalLine.BinRate   = ETGBinJournalLine.BinRate + BinValue;        
    ETGBinJournalLine.modifiedField(fieldNum(ETGBinJournalLine,BinQty));
    ETGBinJournalLine.BinQtyOriginal =  ETGBinJournalLine.BinQty;
    ETGBinJournalLine.BinRateFinal = ETGBinJournalLine.BinQtyOriginal!=0 ? round(ETGBinJournalLine.BinRate /ETGBinJournalLine.BinQtyOriginal,0.01) : 0;
    ETGBinJournalLine.doUpdate();


    ttscommit;

}

/// <summary>
/// creates transfer journal header
/// </summary>
public static InventJournalId CreateTransferJournalHeaderB2B(RecId  Recid)
{
    InventJournalTable inventJournalTable;
    NumberSeq num;
    ETGBinJournalLine         ETGBinJournalLine;
    ETGBin2BinTransferHistory  ETGBin2BinTransferHistory;
    ;

    ttsbegin;

    select ETGBin2BinTransferHistory
        where ETGBin2BinTransferHistory.RecId == Recid;

    select ETGBinJournalLine
        where ETGBinJournalLine.RecId == ETGBin2BinTransferHistory.BinJournalLine;

    inventJournalTable.clear();

    num = new NumberSeq();

    num = NumberSeq::newGetNum(InventParameters::numRefTransferId());

    inventJournalTable.initFromInventJournalName(InventJournalName::find(InventParameters::find().ETGBin2BinTransferJrnName));

    inventJournalTable.Description = 'B2B Journal  No. for '+ETGBinJournalLine.JournalId;

    inventJournalTable.SystemBlocked = true;
    inventJournalTable.ETGBinProcessType = ETGBinProcessType::B2BTransfer;

    inventJournalTable.insert();

