    return inventJournalTable.JournalId;
}

/// <summary>
/// creates B2B transfer journal
/// </summary>
public static void CreateTransferJournalB2B(RecId  Recid,int loopcount,InventJournalId  JournalId)
{
    InventJournalTable inventJournalTable = inventJournalTable::find(JournalId);
    InventJournalTrans inventJournalTrans;
    JournalCheckPost inventJournalCheckPost;
    NumberSeq num;
    boolean _throwserror=true;
    boolean _showinforesult=false;
    InventDim frominventDim,ToinventDim;
    ETGBinJournalLine         ETGBinJournalLine;
    ETGBin2BinTransferHistory  ETGBin2BinTransferHistory;
    ;

    ttsbegin;

    select ETGBin2BinTransferHistory
        where ETGBin2BinTransferHistory.RecId == Recid;

    select ETGBinJournalLine
        where ETGBinJournalLine.RecId == ETGBin2BinTransferHistory.BinJournalLine;


    int linecount=0;

    {

        inventJournalTrans.clear();

        inventJournalTrans.initFromInventJournalTable(inventJournalTable);

        inventJournalTrans.ItemId = ETGBinJournalLine.ItemId;
        inventJournalTrans.LineNum = loopcount;

        frominventDim.InventLocationId= ETGBinJournalLine.Warehouse;
        frominventDim.inventSiteId = ETGBinJournalLine.SiteId;
        frominventDim.wMSLocationId = ETGBinJournalLine.Location;
        frominventDim.configId =   ETGBinJournalLine.Configuration;
        frominventDim.InventSizeId = ETGBinJournalLine.Size;
        frominventDim.InventColorId = ETGBinJournalLine.Colour;
        frominventDim.InventStyleId = ETGBinJournalLine.Style;
        frominventDim.inventBatchId = ETGBin2BinTransferHistory.FromBatch;
        frominventDim.inventSerialId =ETGBinJournalLine.inventSerialId;

        ToinventDim.InventLocationId = ETGBinJournalLine.Warehouse;
        ToinventDim.inventSiteId = ETGBinJournalLine.SiteId;
        ToinventDim.wMSLocationId = ETGBinJournalLine.Location;
        ToinventDim.configId =   ETGBinJournalLine.Configuration;
        ToinventDim.InventSizeId = ETGBinJournalLine.Size;
        ToinventDim.InventColorId = ETGBinJournalLine.Colour;
        ToinventDim.InventStyleId = ETGBinJournalLine.Style;
        ToinventDim.inventBatchId = ETGBin2BinTransferHistory.ToBatch;
        ToinventDim.inventSerialId = ETGBinJournalLine.inventSerialId;


        ToinventDim = InventDim::findOrCreate(ToinventDim);

        frominventDim = InventDim::findOrCreate(frominventDim);

        inventJournalTrans.InventDimId = frominventDim.inventDimId;

        inventJournalTrans.initFromInventTable(InventTable::find(ETGBinJournalLine.ItemId));

        inventJournalTrans.Qty = -ETGBin2BinTransferHistory.TransferQty;
        inventJournalTrans.modifiedField(fieldNum(InventJournalTrans,Qty));

        inventJournalTrans.ToInventDimId = ToinventDim.inventDimId;

        inventJournalTrans.TransDate = SystemDateget();

        inventJournalTrans.ETGBinProcessType = ETGBinProcessType::B2BTransfer;
        inventJournalTrans.ETGRefBinRecid = ETGBin2BinTransferHistory.RecId;

        inventJournalTrans.insert();
        linecount++;
    }

    InventJournalTable  updateInventJournalTable;

    select firstOnly forUpdate updateInventJournalTable
        where updateInventJournalTable.RecId == inventJournalTable.RecId;

    updateInventJournalTable.SystemBlocked = false;
    updateInventJournalTable.NumOfLines = loopcount;
    updateInventJournalTable.update();

    ETGBin2BinTransferHistory.selectForUpdate(true);
    ETGBin2BinTransferHistory.TransferJRNId = inventJournalTable.JournalId;
    ETGBin2BinTransferHistory.doUpdate();

    ttscommit;      
}

/// <summary>
/// Creates bin adjustment journal
/// </summary>
/// <param name = "Recid">RecId</param>
public static void CreateBinAdjustment(RecId  Recid)
{
    InventJournalTable inventJournalTable;
    InventJournalTrans inventJournalTrans;
    JournalCheckPost inventJournalCheckPost;
    NumberSeq num;
    boolean _throwserror=true;
    boolean _showinforesult=false;
    InventDim frominventDim,ToinventDim;
    ETGBinJournalLine         ETGBinJournalLine;
    ETGBinAdjustmentDetails  ETGBinAdjustmentDetails;
    ;

    ttsbegin;

    select ETGBinAdjustmentDetails
        where ETGBinAdjustmentDetails.RecId == Recid;

    select ETGBinJournalLine
        where ETGBinJournalLine.RecId == ETGBinAdjustmentDetails.BinJournalLine;

    inventJournalTable.clear();

    num = new NumberSeq();

    num = NumberSeq::newGetNum(InventParameters::numRefTransferId());

    inventJournalTable.initFromInventJournalName(InventJournalName::find(InventParameters::find().ETGBinAdjustmentJrnName));

    inventJournalTable.Description = 'Bin Adjustment  No. for '+ETGBinJournalLine.JournalId;

    inventJournalTable.SystemBlocked = true;
    inventJournalTable.ETGBinProcessType = ETGBinProcessType::BinAdjustment;

    inventJournalTable.insert();

    int linecount=0;


    {

        inventJournalTrans.clear();

        inventJournalTrans.initFromInventJournalTable(inventJournalTable);

        inventJournalTrans.ItemId = ETGBinJournalLine.ItemId;

        frominventDim.InventLocationId= ETGBinJournalLine.Warehouse;
        frominventDim.inventSiteId = ETGBinJournalLine.SiteId;
        frominventDim.wMSLocationId = ETGBinJournalLine.Location;
        frominventDim.configId =   ETGBinJournalLine.Configuration;
        frominventDim.InventSizeId = ETGBinJournalLine.Size;
        frominventDim.InventColorId = ETGBinJournalLine.Colour;
        frominventDim.InventStyleId = ETGBinJournalLine.Style;
        frominventDim.inventBatchId = ETGBinAdjustmentDetails.ToBatch;
        frominventDim.inventSerialId = ETGBinJournalLine.InventSerialId;

        frominventDim = InventDim::findOrCreate(frominventDim);

        inventJournalTrans.InventDimId = frominventDim.inventDimId;

        inventJournalTrans.initFromInventTable(InventTable::find(ETGBinJournalLine.ItemId));

        inventJournalTrans.Qty = ETGBinAdjustmentDetails.TransferQty;       
        inventJournalTrans.modifiedField(fieldNum(InventJournalTrans,Qty));

        inventJournalTrans.TransDate = SystemDateget();


        inventJournalTrans.ETGBinProcessType = ETGBinProcessType::BinAdjustment;
        inventJournalTrans.ETGRefBinRecid = ETGBinAdjustmentDetails.RecId;

        inventJournalTrans.insert();
        linecount++;
    }

    InventJournalTable  updateInventJournalTable;

    select firstOnly forUpdate updateInventJournalTable
        where updateInventJournalTable.RecId == inventJournalTable.RecId;

    updateInventJournalTable.SystemBlocked = false;
    updateInventJournalTable.NumOfLines = linecount;
    updateInventJournalTable.update();

    ETGBinAdjustmentDetails.selectForUpdate(true);
    ETGBinAdjustmentDetails.TransferJRNId = inventJournalTable.JournalId;
    ETGBinAdjustmentDetails.doUpdate();

    ttscommit;

    if(inventJournalTable.JournalId)
    {
        Info(strFmt('Bin Adjustment Journal %1 has been created.',inventJournalTable.JournalId));
    }
}

