/// <summary>
/// This method contains the logic for calculating costprice
/// </summary>
/// <param name = "_itemId">ItemId</param>
/// <param name = "_inventDim">InventDim</param>
/// <returns>CostPrice</returns>
public static CostPrice getItemCostPrice(ItemId _itemId, InventDim _inventDim)
{
    InventSum                   inventSum;
    CostPrice                   priceLoc;
    CostPrice                   costPrice;
    InventOnhand                inventOnHand;
    InventDimParm               inventDimParm;
    InventTransferLine_IN       inventTransferLineIN;

    InventDimGroupSetup::newItemId(_itemId).inventDimParmActivefinancialInventory(inventDimParm);
    inventOnHand = InventOnhand::newParameters(_itemId, _inventDim, inventDimParm);
    inventSum    = inventOnhand.inventSum();

    if (inventSum)
    {
        priceLoc = inventSum.costPricePcs();

        if (!priceLoc)
        {
            priceLoc = InventTable::findCostPcsPrice(_itemId, _inventDim.inventDimId);
        }
    }
    else
    {
        priceLoc = InventTable::findCostPcsPrice(_itemId, _inventDim.inventDimId);
    }
    costPrice = CurrencyExchangeHelper::price(priceLoc, CompanyInfoHelper::standardCurrency());

    return costPrice;
}

public static void lookupSubVertical(FormControl _formControl, str _filterStr)
{

    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tableNum(DimensionAttributeValue),_formControl);

    Query                   query = new Query();
    QueryBuildDataSource    queryBuildDataSource;
    QueryBuildRange         queryBuildRange;


    queryBuildDataSource = query.addDataSource(tableNum(DimensionAttributeValue));

    queryBuildRange = queryBuildDataSource.addRange(fieldNum(DimensionAttributeValue,DimensionAttribute));

    LedgerParameters LedgerParameters;

    select firstonly LedgerParameters
                   where LedgerParameters.DataAreaId == curExt();

    DimensionAttribute dimensionAttribute      = DimensionAttribute::findByName(LedgerParameters.ETGCostDistributionSubVerticalDimension);

    queryBuildRange.value(queryValue(dimensionAttribute.RecId));


    sysTableLookup.addLookupfield(fieldNum(DimensionAttributeValue,DisplayValue));
    //sysTableLookup.addLookupfield(fieldNum(DimensionAttributeValue,name));


    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();

}

